// Extract ISBN and file type from filename
// Expected format: 9781234567890_text.pdf or 9781234567890_text.png
const fileName = $json.name || '';
const match = fileName.match(/^(\d{13})_text\.(pdf|png)$/i);

if (!match) {
  throw new Error(`Invalid filename format: "${fileName}". Expected: {13-digit-ISBN}_text.pdf or .png`);
}

return [{
  json: {
    isbn: match[1],
    fileType: match[2].toLowerCase(),
    fileId: $json.id,
    fileName: fileName,
    fileUrl: `https://drive.google.com/file/d/${$json.id}/view`
  }
}];

// Pass through PNG binary data — merge point for PDF and PNG paths
const items = $input.all();
return items.map(item => ({
  json: {
    isbn: $('Extract ISBN').item.json.isbn,
    fileType: $('Extract ISBN').item.json.fileType,
    fileId: $('Extract ISBN').item.json.fileId,
    fileName: $('Extract ISBN').item.json.fileName,
    fileUrl: $('Extract ISBN').item.json.fileUrl
  },
  binary: item.binary
}));

const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];

if (!binaryKey) {
  throw new Error('No binary data found.');
}

const binaryData = item.binary[binaryKey];
const base64 = binaryData.data;
const mimeType = binaryData.mimeType || 'image/png';

return [{
  json: {
    ...item.json,
    base64Image: base64,
    mimeType: mimeType,
    dataUri: `data:${mimeType};base64,${base64}`
  }
}];

// Analyze OCR bounding box data to detect badge zone violations
// Badge zone = bottom 5% of front cover height (~9mm at 300 DPI standard)
const result = $input.first().json;
const isbn = $('Convert to Base64').item.json.isbn;
const fileUrl = $('Convert to Base64').item.json.fileUrl;

// Handle OCR errors
if (result.IsErroredOnProcessing || !result.ParsedResults?.length) {
  const errMsg = result.ErrorMessage?.[0] || 'OCR processing failed';
  return [{
    json: {
      isbn,
      fileUrl,
      status: 'REVIEW_NEEDED',
      confidence: 0,
      badge_area_clear: false,
      author_name_detected: '',
      issues_json: JSON.stringify([{
        type: 'quality_issue',
        severity: 'warning',
        description: 'OCR failed: ' + errMsg,
        correction: 'Ensure the image is a clear PNG/PDF at min 300 DPI and under 1MB file size'
      }]),
      correction_instructions: '1. [WARNING] quality_issue: OCR failed: ' + errMsg + ' → Fix: Ensure image is clear PNG/PDF, min 300 DPI, under 1MB'
    }
  }];
}

const lines = result.ParsedResults[0]?.TextOverlay?.Lines || [];

// Collect all words with pixel bounding boxes
const allWords = [];
for (const line of lines) {
  for (const word of (line.Words || [])) {
    const text = (word.WordText || '').trim();
    if (!text) continue;
    allWords.push({
      text,
      top: parseFloat(word.Top) || 0,
      bottom: (parseFloat(word.Top) || 0) + (parseFloat(word.Height) || 0),
      left: parseFloat(word.Left) || 0,
      right: (parseFloat(word.Left) || 0) + (parseFloat(word.Width) || 0)
    });
  }
}

if (!allWords.length) {
  return [{
    json: {
      isbn,
      fileUrl,
      status: 'REVIEW_NEEDED',
      confidence: 50,
      badge_area_clear: false,
      author_name_detected: '',
      issues_json: JSON.stringify([{
        type: 'quality_issue',
        severity: 'warning',
        description: 'No text detected in image',
        correction: 'Ensure the cover has readable text and is not too small or blurry'
      }]),
      correction_instructions: '1. [WARNING] quality_issue: No text detected → Fix: Ensure cover has readable text'
    }
  }];
}

// Estimate full image dimensions from outermost word positions
const totalWidth = Math.max(...allWords.map(w => w.right));
const totalHeight = Math.max(...allWords.map(w => w.bottom));

// If width > height it is a spread — analyse right half (front cover) only
const isSpread = totalWidth > totalHeight;
const frontCoverMinLeft = isSpread ? totalWidth * 0.5 : 0;

let frontWords = allWords.filter(w => w.right > frontCoverMinLeft);
if (!frontWords.length) frontWords = allWords;

// Front cover dimensions
const fcHeight = Math.max(...frontWords.map(w => w.bottom));
const fcWidth = isSpread ? totalWidth / 2 : totalWidth;

// Badge zone threshold — bottom 5% of cover height
const badgeZoneTop = fcHeight * 0.95;

// Words inside badge zone
const badgeWords = frontWords.filter(w => w.bottom > badgeZoneTop);

// Award phrase — the ONLY text permitted in the badge zone
const awardPhrase = 'winner of the 21st century emily dickinson award';
const awardWordSet = new Set(awardPhrase.split(' '));

// Violations = words in badge zone that are NOT part of the award phrase
const violations = badgeWords.filter(w => {
  const clean = w.text.toLowerCase().replace(/[^a-z0-9]/g, '');
  return clean.length > 1 && !awardWordSet.has(clean);
});

// Margin check — text within 2% of cover edges (~3mm at standard cover size)
const marginPx = fcWidth * 0.02;
const leftEdge = frontCoverMinLeft + marginPx;
const rightEdge = frontCoverMinLeft + fcWidth - marginPx;
const topEdge = marginPx;

const marginViolations = frontWords.filter(w =>
  w.bottom < badgeZoneTop &&
  (w.left < leftEdge || w.right > rightEdge || w.top < topEdge)
);

// Build issues array
const issues = [];

if (violations.length > 0) {
  const violText = violations.map(w => w.text).join(' ');
  issues.push({
    type: 'badge_overlap',
    severity: 'critical',
    description: 'Text "' + violText + '" found in Award Badge Zone (bottom 5% of cover). Only the award badge text is permitted here.',
    correction: 'Move this text above the badge zone. The bottom strip must contain only the award badge text.'
  });
}

if (marginViolations.length > 0) {
  issues.push({
    type: 'margin_violation',
    severity: 'warning',
    description: 'Text detected within 3mm of the cover edge',
    correction: 'Ensure all text has at least 3mm clearance from all four cover edges'
  });
}

const hasCritical = issues.some(i => i.severity === 'critical');
const status = hasCritical ? 'REVIEW_NEEDED' : 'PASS';
const confidence = hasCritical ? 75 : 95;

const correctionLines = issues.map(
  (i, idx) => (idx + 1) + '. [' + i.severity.toUpperCase() + '] ' + i.type + ': ' + i.description + ' → Fix: ' + i.correction
).join('\n');

return [{
  json: {
    isbn,
    fileUrl,
    status,
    confidence,
    badge_area_clear: violations.length === 0,
    author_name_detected: violations.map(w => w.text).join(' '),
    issues_json: JSON.stringify(issues),
    correction_instructions: correctionLines || 'No issues found.',
    raw_ocr_text: (result.ParsedResults[0]?.ParsedText || '').substring(0, 500)
  }
}];

// Merge validation results with author data from Airtable
const validationData = $('Analyze OCR Results').item.json;
const authorName = $input.first().json.Author_Name || validationData.author_name_detected || 'Unknown Author';
const authorEmail = $input.first().json.Author_Email || null;
const bookTitle = $input.first().json.Book_Title || 'Your Book';

return [{
  json: {
    ...validationData,
    author_name: authorName,
    author_email: authorEmail,
    book_title: bookTitle,
    has_author_email: !!authorEmail
  }
}];
